class TweetCounts:

    def __init__(self):
        self.tweets = defaultdict(dict)

    def recordTweet(self, tweetName: str, time: int) -> None:
        if tweetName not in self.tweets:
            self.tweets[tweetName] = {}
        if time not in self.tweets[tweetName]:
            self.tweets[tweetName][time] = 1
        else:
            self.tweets[tweetName][time] += 1

    def getTweetCountsPerFrequency(self, freq: str, tweetName: str, startTime: int, endTime: int) -> List[int]:
        result = []
        if tweetName not in self.tweets:
            return result
        if freq == "minute":
            chunk_size = 60
        elif freq == "hour":
            chunk_size = 3600
        else:
            chunk_size = 86400
        for time in range(startTime, endTime + 1):
            count = 0
            while time - chunk_size >= startTime:
                if time - chunk_size in self.tweets[tweetName]:
                    count += self.tweets[tweetName][time - chunk_size]
                time -= chunk_size
            if time in self.tweets[tweetName]:
                count += self.tweets[tweetName][time]
            result.append(count)
        return result
